import { IMessageComposer } from '@nitrots/nitro-renderer';

export class DoorDashOrdersRequestComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor() {
        // no payload needed – server just replies with current orders
        this._data = [];
        console.log('[📤] DoorDashOrdersRequestComposer sent');
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
